use std::io::stdin;

fn main() {
    let mut input = String::new();
    stdin().read_line(&mut input).unwrap();

    let emploees: i32 = input.trim().parse().unwrap();
    let mut counter = 0;

    for leaders in 1..emploees {
        if (emploees - leaders) % leaders == 0 {
            counter = counter + 1;
        }
    }

    println!("{}", counter);
}
